@startuml
skinparam classAttributeIconSize 0
skinparam classFontStyle italic
skinparam classBackgroundColor #F5F5F5
skinparam classBorderColor #333333
skinparam classFontColor #333333
skinparam stereotypeCBackgroundColor #A8D5BA
skinparam stereotypeCBorderColor #333333
skinparam stereotypeCFontColor #333333
skinparam stereotypeIBackgroundColor #D4C4E8
skinparam stereotypeIBorderColor #333333
skinparam stereotypeIFontColor #333333
skinparam stereotypeABackgroundColor #A8D5BA
skinparam stereotypeABorderColor #333333
skinparam stereotypeAFontColor #333333

class "OrderPizza" as OrderPizza <<C>> {
}

class "AbsFactory" as AbsFactory <<I>> {
  + Pizza createPizza()
}

class "Pizza" as Pizza <<A>> {
  + void prepare()
  + void bake()
  + void cut()
  + void box()
}

class "LDPepperPizza" as LDPepperPizza <<C>> {
}

class "LDCheesePizza" as LDCheesePizza <<C>> {
}

class "BJPepperPizza" as BJPepperPizza <<C>> {
}

class "BJCheesePizza" as BJCheesePizza <<C>> {
}

class "LDFactory" as LDFactory <<C>> {
}

class "BJFactory" as BJFactory <<C>> {
}

OrderPizza --|> AbsFactory : aggregation
AbsFactory <|-- LDFactory
AbsFactory <|-- BJFactory
Pizza <|-- LDPepperPizza
Pizza <|-- LDCheesePizza
Pizza <|-- BJPepperPizza
Pizza <|-- BJCheesePizza
LDFactory ..> LDPepperPizza : creates
LDFactory ..> LDCheesePizza : creates
BJFactory ..> BJPepperPizza : creates
BJFactory ..> BJCheesePizza : creates
@enduml
